package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades;

import java.util.Comparator;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Objects;

/** Deterministic identity for memo-local proof lineages. */
final class MemoProofLineage {

	private static final Comparator<RuleProof> PROOF_ORDER = Comparator.comparing(MemoProofLineage::canonicalProof);

	private MemoProofLineage() {
	}

	static List<RuleProof> normalize(List<RuleProof> proofs) {
		if (proofs == null || proofs.isEmpty()) {
			return List.of();
		}
		return new LinkedHashSet<>(proofs).stream()
				.filter(Objects::nonNull)
				.sorted(PROOF_ORDER)
				.toList();
	}

	private static String canonicalProof(RuleProof proof) {
		StringBuilder key = new StringBuilder();
		append(key, proof.ruleId());
		append(key, proof.kind().name());
		append(key, proof.semanticScope());
		proof.facts().stream().sorted().forEach(fact -> append(key, fact));
		append(key, proof.reason());
		RewriteCertificate certificate = proof.certificate();
		if (certificate == null) {
			append(key, "no-certificate");
			return key.toString();
		}
		append(key, certificate.ruleId());
		append(key, certificate.originalNodeId());
		append(key, certificate.replacementNodeId());
		RewriteSafety safety = certificate.safety();
		append(key, Boolean.toString(safety.preservedVisibleVars()));
		append(key, Boolean.toString(safety.preservedMultiplicity()));
		append(key, Boolean.toString(safety.preservedOrder()));
		append(key, Boolean.toString(safety.preservedErrors()));
		append(key, Boolean.toString(safety.preservedGraphScope()));
		certificate.assumptions().stream().map(Enum::name).sorted().forEach(assumption -> append(key, assumption));
		return key.toString();
	}

	private static void append(StringBuilder target, String component) {
		String value = component == null ? "" : component;
		target.append(value.length()).append(':').append(value);
	}
}
